SELECT access_type, access_location 
FROM access_logs 
WHERE access_date = (SELECT MAX(access_date) FROM access_logs);

SELECT packet_type_name
FROM packet_types
WHERE packet_type_id = 0;

SELECT v.vehicle_name, p.packet_type
FROM vehicles AS v
JOIN packets AS p ON v.vehicle_id = p.vehicle_id;

SELECT alert_type
FROM packet_alerts
WHERE alert_severity = 'critical';

SELECT alert_type, alert_severity, alert_date
FROM network_alerts
WHERE alert_date BETWEEN '2023-05-01' AND '2023-05-31';

SELECT v.vehicle_id, p.packet_type, p.packet_acknowledgment_number
FROM vehicles v
INNER JOIN packets p ON v.vehicle_id = p.vehicle_id;

SELECT vehicle_name, vehicle_type
FROM vehicles
ORDER BY vehicle_name;
